SELECT b.user_id, b.room_no FROM Bookings b WHERE b.booking_date = ( SELECT MAX(b2.booking_date) FROM Bookings b2 WHERE b2.user_id = b.user_id );
SELECT bc.booking_id,SUM(bc.item_quantity * i.item_rate) AS total_billing FROM booking_commercials bc JOIN items i ON bc.item_id = i.item_id JOIN bookings b ON bc.booking_id = b.booking_id WHERE EXTRACT(MONTH FROM b.booking_date) = 11 AND EXTRACT(YEAR FROM b.booking_date) = 2021 GROUP BY bc.booking_id;
SELECT bc.bill_id,SUM(bc.item_quantity * i.item_rate) AS bill_amount JOIN items i ON bc.item_id = i.item_id WHERE EXTRACT(MONTH FROM bc.bill_date) = 10 AND EXTRACT(YEAR FROM bc.bill_date) = 2021 GROUP BY bc.bill_id HAVING SUM(bc.item_quantity * i.item_rate) > 1000;
SELECT month, item_id, total_qty, order_type FROM ( SELECT EXTRACT(MONTH FROM o.order_date) AS month,oi.item_id,SUM(oi.quantity) AS total_qty,RANK() OVER (PARTITION BY EXTRACT(MONTH FROM o.order_date) ORDER BY SUM(oi.quantity) DESC) AS rnk_desc, RANK() OVER (PARTITION BY EXTRACT(MONTH FROM o.order_date) ORDER BY SUM(oi.quantity) ASC) AS rnk_asc FROM Orders o JOIN Order_Items oi ON o.order_id = oi.order_id WHERE EXTRACT(YEAR FROM o.order_date) = 2021 GROUP BY EXTRACT(MONTH FROM o.order_date), oi.item_id ) sub WHERE rnk_desc = 1 OR rnk_asc = 1;
SELECT month, bill_id, bill_amount FROM (SELECT EXTRACT(MONTH FROM bc.bill_date) AS month,bc.bill_id,SUM(bc.item_quantity * i.item_rate) AS bill_amount, DENSE_RANK() OVER ( PARTITION BY EXTRACT(MONTH FROM bc.bill_date) ORDER BY SUM(bc.item_quantity * i.item_rate) DESC ) AS rnk FROM booking_commercials bc JOIN items i ON bc.item_id = i.item_id WHERE EXTRACT(YEAR FROM bc.bill_date) = 2021 GROUP BY EXTRACT(MONTH FROM bc.bill_date), bc.bill_id ) t WHERE rnk = 2;
